class Solution {
public:
    string discountPrices(string sentence, int discount) {
        vector<string> words;
        string word;
        for (char c : sentence) {
            if (c == ' ') {
                words.push_back(word);
                word.clear();
            } else {
                word += c;
            }
        }
        words.push_back(word);

        for (int i = 0; i < words.size(); i++) {
            if (words[i][0] == '$') {
                double price = stod(words[i].substr(1));
                double discountAmount = price * (discount / 100.0);
                double discountedPrice = price - discountAmount;
                words[i] = "$" + to_string(int(discountedPrice * 100)) + "." + to_string(int((discountedPrice * 100) - int(discountedPrice * 100)));
            }
        }

        string result;
        for (const string& word : words) {
            result += word + " ";
        }
        result.pop_back(); // remove the trailing space

        return result;
    }
};
